&#34;) send_message(server, &#34;What is the encryption key? &#34;) key_answer = server.recv(4096).decode().strip() try: if key_answer == key: send_message(server, &#34;Congrats! That is the correct key! Here is flag 2: &#34; + flag + &#34;
